/**
 * Summary analytics across the entire system.
 */
export interface AnalyticsSummary {
  totalUsers: number;
  totalOrders: number;
  revenue: number;
  activeUsers: number;
}

/**
 * Per-user analytics breakdown.
 */
export interface UserAnalytics {
  userId: string;
  orderCount: number;
  totalSpent: number;
  lastActive: Date;
}

/**
 * A single data point in a time-series trend.
 */
export interface TrendPoint {
  timestamp: Date;
  metric: string;
  value: number;
}

import type { AnalyticsSummary, UserAnalytics, TrendPoint } from '../models/analytics.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private userRepository: UserRepository,
    private orderRepository: OrderRepository,
  ) {}

  /**
   * Get aggregate summary statistics.
   */
  getSummary(): AnalyticsSummary {
    this.logger.info('Generating analytics summary');

    const users = this.userRepository.findAll();
    const orders = this.orderRepository.findAll();

    const revenue = orders.reduce((sum, order) => sum + order.total, 0);

    const userIdsWithOrders = new Set(orders.map((o) => o.userId));
    const activeUsers = userIdsWithOrders.size;

    return {
      totalUsers: users.length,
      totalOrders: orders.length,
      revenue,
      activeUsers,
    };
  }

  /**
   * Get analytics for a specific user.
   */
  getUserAnalytics(userId: string): UserAnalytics {
    this.logger.info(`Generating analytics for user: ${userId}`);

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const orders = this.orderRepository.findByUserId(userId);
    const totalSpent = orders.reduce((sum, order) => sum + order.total, 0);

    const lastActive = orders.length > 0
      ? orders.reduce((latest, order) =>
          order.createdAt > latest ? order.createdAt : latest,
        orders[0].createdAt)
      : user.createdAt;

    return {
      userId,
      orderCount: orders.length,
      totalSpent,
      lastActive,
    };
  }

  /**
   * Get time-series trend data for a metric within a date range.
   */
  getTrends(metric: string, startDate: Date, endDate: Date): TrendPoint[] {
    this.logger.info(`Generating trends for metric: ${metric}`);

    if (metric === 'revenue') {
      return this.getRevenueTrends(startDate, endDate);
    }

    if (metric === 'orders') {
      return this.getOrderTrends(startDate, endDate);
    }

    if (metric === 'users') {
      return this.getUserTrends(startDate, endDate);
    }

    throw new Error(`Unknown metric: ${metric}`);
  }

  private getRevenueTrends(startDate: Date, endDate: Date): TrendPoint[] {
    const orders = this.orderRepository.findAll().filter(
      (o) => o.createdAt >= startDate && o.createdAt <= endDate,
    );

    return this.aggregateByDay(orders, 'revenue', (dayOrders) =>
      dayOrders.reduce((sum, o) => sum + o.total, 0),
    );
  }

  private getOrderTrends(startDate: Date, endDate: Date): TrendPoint[] {
    const orders = this.orderRepository.findAll().filter(
      (o) => o.createdAt >= startDate && o.createdAt <= endDate,
    );

    return this.aggregateByDay(orders, 'orders', (dayOrders) => dayOrders.length);
  }

  private getUserTrends(startDate: Date, endDate: Date): TrendPoint[] {
    const users = this.userRepository.findAll().filter(
      (u) => u.createdAt >= startDate && u.createdAt <= endDate,
    );

    return this.aggregateByDay(users, 'users', (dayUsers) => dayUsers.length);
  }

  private aggregateByDay<T extends { createdAt: Date }>(
    items: T[],
    metric: string,
    aggregator: (dayItems: T[]) => number,
  ): TrendPoint[] {
    const byDay = new Map<string, T[]>();

    for (const item of items) {
      const dayKey = item.createdAt.toISOString().split('T')[0];
      const existing = byDay.get(dayKey) ?? [];
      existing.push(item);
      byDay.set(dayKey, existing);
    }

    return Array.from(byDay.entries())
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([day, dayItems]) => ({
        timestamp: new Date(day),
        metric,
        value: aggregator(dayItems),
      }));
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

describe('AnalyticsService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;

  const makeUser = (overrides?: Partial<User>): User => ({
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date('2024-01-01'),
    updatedAt: new Date('2024-01-01'),
    ...overrides,
  });

  const makeOrder = (overrides?: Partial<Order>): Order => ({
    id: 'order-1',
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 25 }],
    total: 50,
    status: 'pending',
    createdAt: new Date('2024-01-15'),
    updatedAt: new Date('2024-01-15'),
    ...overrides,
  });

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(userRepo, orderRepo);
  });

  describe('getSummary', () => {
    it('should return zeros when no data exists', () => {
      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(0);
      expect(summary.totalOrders).toBe(0);
      expect(summary.revenue).toBe(0);
      expect(summary.activeUsers).toBe(0);
    });

    it('should aggregate stats from users and orders', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      userRepo.save(makeUser({ id: 'user-2', email: 'bob@example.com' }));
      userRepo.save(makeUser({ id: 'user-3', email: 'carol@example.com' }));

      orderRepo.save(makeOrder({ id: 'order-1', userId: 'user-1', total: 100 }));
      orderRepo.save(makeOrder({ id: 'order-2', userId: 'user-1', total: 50 }));
      orderRepo.save(makeOrder({ id: 'order-3', userId: 'user-2', total: 75 }));

      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(3);
      expect(summary.totalOrders).toBe(3);
      expect(summary.revenue).toBe(225);
      expect(summary.activeUsers).toBe(2);
    });
  });

  describe('getUserAnalytics', () => {
    it('should throw for non-existent user', () => {
      expect(() => service.getUserAnalytics('no-such-user')).toThrow('User not found');
    });

    it('should return analytics for user with no orders', () => {
      const user = makeUser({ createdAt: new Date('2024-03-01') });
      userRepo.save(user);

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.userId).toBe('user-1');
      expect(analytics.orderCount).toBe(0);
      expect(analytics.totalSpent).toBe(0);
      expect(analytics.lastActive).toEqual(new Date('2024-03-01'));
    });

    it('should calculate per-user order stats', () => {
      userRepo.save(makeUser());
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2024-02-01') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 50, createdAt: new Date('2024-03-15') }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.orderCount).toBe(2);
      expect(analytics.totalSpent).toBe(150);
      expect(analytics.lastActive).toEqual(new Date('2024-03-15'));
    });
  });

  describe('getTrends', () => {
    it('should throw for unknown metric', () => {
      expect(() =>
        service.getTrends('unknown', new Date('2024-01-01'), new Date('2024-12-31')),
      ).toThrow('Unknown metric: unknown');
    });

    it('should return revenue trends grouped by day', () => {
      userRepo.save(makeUser());
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2024-01-15T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 50, createdAt: new Date('2024-01-15T14:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o3', total: 75, createdAt: new Date('2024-01-16T09:00:00Z') }));

      const trends = service.getTrends('revenue', new Date('2024-01-01'), new Date('2024-01-31'));

      expect(trends).toHaveLength(2);
      expect(trends[0].metric).toBe('revenue');
      expect(trends[0].value).toBe(150);
      expect(trends[1].value).toBe(75);
    });

    it('should return order count trends grouped by day', () => {
      userRepo.save(makeUser());
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2024-01-15') }));
      orderRepo.save(makeOrder({ id: 'o2', createdAt: new Date('2024-01-15') }));
      orderRepo.save(makeOrder({ id: 'o3', createdAt: new Date('2024-01-16') }));

      const trends = service.getTrends('orders', new Date('2024-01-01'), new Date('2024-01-31'));

      expect(trends).toHaveLength(2);
      expect(trends[0].value).toBe(2);
      expect(trends[1].value).toBe(1);
    });

    it('should return user registration trends grouped by day', () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2024-01-10') }));
      userRepo.save(makeUser({ id: 'u2', email: 'b@example.com', createdAt: new Date('2024-01-10') }));
      userRepo.save(makeUser({ id: 'u3', email: 'c@example.com', createdAt: new Date('2024-01-12') }));

      const trends = service.getTrends('users', new Date('2024-01-01'), new Date('2024-01-31'));

      expect(trends).toHaveLength(2);
      expect(trends[0].value).toBe(2);
      expect(trends[1].value).toBe(1);
    });

    it('should filter trends by date range', () => {
      userRepo.save(makeUser());
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2024-01-10') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200, createdAt: new Date('2024-02-15') }));
      orderRepo.save(makeOrder({ id: 'o3', total: 300, createdAt: new Date('2024-03-20') }));

      const trends = service.getTrends('revenue', new Date('2024-02-01'), new Date('2024-02-28'));

      expect(trends).toHaveLength(1);
      expect(trends[0].value).toBe(200);
    });
  });
});

